mapper.select:
SELECT br.id, br.item_id, i.name AS item_name, i.category, i.spec, br.cabinet_id, c.cabinet_no, c.name AS cabinet_name, br.slot_id, cs.slot_no, br.quantity, br.returned_quantity, (br.quantity - br.returned_quantity) AS pending_quantity, br.borrower, br.borrow_operator, br.borrow_operator_no, br.borrow_operator_name, br.return_operator, br.return_operator_no, br.return_operator_name, br.borrow_time, br.expected_return_time, br.return_time, br.status, br.remark FROM item_borrow_record br LEFT JOIN item i ON br.item_id = i.id AND i.deleted = 0 LEFT JOIN cabinet c ON br.cabinet_id = c.id AND c.deleted = 0 LEFT JOIN cabinet_slot cs ON br.slot_id = cs.id AND cs.deleted = 0 WHERE br.deleted = 0
AND br.status = #{status}
AND br.item_id = #{itemId}
AND br.borrower LIKE CONCAT('%', #{borrower}, '%')
ORDER BY br.borrow_time DESC, br.id DESC
